customCSS:
/* Wood Paneling - Walnut & Mahogany */
@import url('https://fonts.googleapis.com/css2?family=Libre+Baskerville:wght@400;700&family=Source+Sans+3:wght@300;400;600&family=Source+Code+Pro&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 30% 10%, rgba(140, 95, 60, 0.08), transparent),
    radial-gradient(ellipse 500px 350px at 70% 90%, rgba(100, 68, 40, 0.06), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(140, 95, 60, 0.22);
  background: rgba(36, 26, 16, 0.92);
}

.stat-card::before {
  background: linear-gradient(90deg, #8b5e3c, #c47a50, #c86830);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(196, 122, 80, 0.4);
  box-shadow: 0 4px 20px rgba(140, 95, 60, 0.15);
}

.stat-value {
  text-shadow: none;
}

.celebration-title {
  color: #deb070 !important;
  text-shadow: 0 0 20px rgba(222, 176, 112, 0.4);
}

.miner-card, .health-card, .lifetime-card {
  background: rgba(36, 26, 16, 0.75);
  border: 1px solid rgba(140, 95, 60, 0.14);
}

.miner-card:hover {
  border-color: rgba(196, 122, 80, 0.3);
}
